import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str
    quantity: int = 1


@dataclass
class Player:
    player_id: str
    websocket: WebSocketServerProtocol
    inventory: Dict[str, Item] = field(default_factory=dict)
    lock: asyncio.Lock = field(default_factory=asyncio.Lock)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.server_lock = asyncio.Lock()

    async def register_player(self, websocket: WebSocketServerProtocol) -> Player:
        player_id = str(uuid.uuid4())
        player = Player(player_id=player_id, websocket=websocket)
        async with self.server_lock:
            self.players[player_id] = player
        return player

    async def unregister_player(self, player_id: str):
        async with self.server_lock:
            player = self.players.pop(player_id, None)
            if player:
                for item_id in list(player.inventory.keys()):
                    self.items.pop(item_id, None)

    async def add_item(self, owner_id: str, name: str, quantity: int = 1) -> Item:
        item_id = str(uuid.uuid4())
        item = Item(item_id=item_id, name=name, owner_id=owner_id, quantity=quantity)
        async with self.server_lock:
            self.items[item_id] = item
            player = self.players.get(owner_id)
            if player:
                async with player.lock:
                    player.inventory[item_id] = item
        return item

    async def transfer_item(self, from_id: str, to_id: str, item_id: str, quantity: int = 1) -> Dict[str, Any]:
        if from_id == to_id:
            return {"ok": False, "error": "cannot_transfer_to_self"}

        player_a = self.players.get(from_id)
        player_b = self.players.get(to_id)
        if not player_a or not player_b:
            return {"ok": False, "error": "player_not_found"}

        first, second = (player_a, player_b) if from_id < to_id else (player_b, player_a)

        async with first.lock:
            async with second.lock:
                item = player_a.inventory.get(item_id)
                if not item:
                    return {"ok": False, "error": "item_not_found"}
                if quantity <= 0:
                    return {"ok": False, "error": "invalid_quantity"}
                if item.quantity < quantity:
                    return {"ok": False, "error": "insufficient_quantity"}

                if item.quantity == quantity:
                    del player_a.inventory[item_id]
                    item.owner_id = to_id
                    player_b.inventory[item_id] = item
                else:
                    item.quantity -= quantity
                    moved_item = Item(
                        item_id=str(uuid.uuid4()),
                        name=item.name,
                        owner_id=to_id,
                        quantity=quantity,
                    )
                    player_b.inventory[moved_item.item_id] = moved_item
                    async with self.server_lock:
                        self.items[moved_item.item_id] = moved_item

                async with self.server_lock:
                    self.items[item_id] = item

                return {
                    "ok": True,
                    "from": from_id,
                    "to": to_id,
                    "item_id": item_id,
                    "quantity": quantity,
                }

    async def handle_message(self, player: Player, data: Dict[str, Any]):
        msg_type = data.get("type")

        if msg_type == "set_name":
            name = str(data.get("name", "")).strip()
            await player.websocket.send(json.dumps({"type": "set_name_result", "ok": bool(name), "name": name}))
            return

        if msg_type == "create_item":
            name = str(data.get("name", "")).strip()
            quantity = int(data.get("quantity", 1))
            if not name or quantity <= 0:
                await player.websocket.send(json.dumps({"type": "create_item_result", "ok": False, "error": "invalid_item"}))
                return
            item = await self.add_item(player.player_id, name, quantity)
            await player.websocket.send(json.dumps({
                "type": "create_item_result",
                "ok": True,
                "item": {
                    "item_id": item.item_id,
                    "name": item.name,
                    "owner_id": item.owner_id,
                    "quantity": item.quantity,
                }
            }))
            return

        if msg_type == "transfer_item":
            target_id = str(data.get("to_player_id", "")).strip()
            item_id = str(data.get("item_id", "")).strip()
            quantity = int(data.get("quantity", 1))
            result = await self.transfer_item(player.player_id, target_id, item_id, quantity)
            await player.websocket.send(json.dumps({"type": "transfer_item_result", **result}))
            if result.get("ok"):
                target_player = self.players.get(target_id)
                if target_player:
                    await target_player.websocket.send(json.dumps({
                        "type": "inventory_update",
                        "reason": "received_item",
                        "from_player_id": player.player_id,
                        "item_id": item_id,
                        "quantity": quantity,
                    }))
            return

        if msg_type == "inventory":
            async with player.lock:
                items = [
                    {"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id, "quantity": item.quantity}
                    for item in player.inventory.values()
                ]
            await player.websocket.send(json.dumps({"type": "inventory_result", "ok": True, "items": items}))
            return

        await player.websocket.send(json.dumps({"type": "error", "error": "unknown_message_type"}))

    async def connection_handler(self, websocket: WebSocketServerProtocol):
        player = await self.register_player(websocket)
        try:
            await websocket.send(json.dumps({"type": "welcome", "player_id": player.player_id}))
            async for message in websocket:
                try:
                    data = json.loads(message)
                    if isinstance(data, dict):
                        await self.handle_message(player, data)
                    else:
                        await websocket.send(json.dumps({"type": "error", "error": "invalid_payload"}))
                except json.JSONDecodeError:
                    await websocket.send(json.dumps({"type": "error", "error": "invalid_json"}))
                except Exception as e:
                    await websocket.send(json.dumps({"type": "error", "error": "server_error", "detail": str(e)}))
        finally:
            await self.unregister_player(player.player_id)


async def main(host: str = "0.0.0.0", port: int = 8765):
    server = GameServer()
    async with websockets.serve(server.connection_handler, host, port):
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())